// 临时冒烟文件:niceeval 节点 1.5(defineScoreEval)验收用,验证后删除,不提交进 MemoryBench。
import { defineScoreEval } from "niceeval";
import { includes } from "niceeval/expect";

export default defineScoreEval({
  description: "smoke: checkpoint-style points scoring",
  async test(t) {
    await t.send("call the search tool, then reply with the word done");
    t.calledTool("search").points(2); // checkpoint 1: 2 分
    t.check(t.reply, includes("done")).points(3); // checkpoint 2: 3 分
    t.score("bonus", 1); // 直接给分:1 分
  },
});
